module RefModule(
    output reg X,
    input wire A,
    input wire B,
    input wire C,
    input wire D,
    input wire VPWR,
    input wire VGND,
    input wire VPB,
    input wire VNB
);wire or_output;

    // Simple four-input OR gate implementation
  wire temp1_A | B | C = A | B | C;
  wire temp2_D = D;
  assign or_output = temp1_A | B | C | temp2_D;

    always @ (or_output) begin
        X = or_output;
    end

endmodule
